import{_ as t,o as a,c as n,a4 as s}from"./chunks/framework.CKa9pyC8.js";const b=JSON.parse('{"title":"Tables","description":"Create and edit Markdown tables using the inline table editor with row/column controls and alignment settings.","frontmatter":{"title":"Tables","description":"Create and edit Markdown tables using the inline table editor with row/column controls and alignment settings.","keywords":"tables, markdown table, inline table editor, columns, rows, alignment","category":"Editor"},"headers":[],"relativePath":"editor/tables.md","filePath":"editor/tables.md","lastUpdated":1784643630000}'),l={name:"editor/tables.md"};function i(o,e,r,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="tables" tabindex="-1">Tables <a class="header-anchor" href="#tables" aria-label="Permalink to &quot;Tables&quot;">​</a></h1><p>Notely includes an inline table editor that lets you edit Markdown tables in a spreadsheet-style grid without touching the raw Markdown syntax.</p><h2 id="create-a-table" tabindex="-1">Create a Table <a class="header-anchor" href="#create-a-table" aria-label="Permalink to &quot;Create a Table&quot;">​</a></h2><p><strong>Option 1 — Toolbar:</strong></p><ol><li>Click the <strong>Table</strong> button in the editor toolbar.</li><li>A basic table skeleton is inserted at the cursor.</li></ol><p><strong>Option 2 — Type Markdown directly:</strong></p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Header A | Header B | Header C |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|---|---|---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Cell 1 | Cell 2 | Cell 3 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Cell 4 | Cell 5 | Cell 6 |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="open-the-inline-table-editor" tabindex="-1">Open the Inline Table Editor <a class="header-anchor" href="#open-the-inline-table-editor" aria-label="Permalink to &quot;Open the Inline Table Editor&quot;">​</a></h2><p>When your cursor is inside a Markdown table in Edit mode, the <strong>inline table editor</strong> opens automatically as an overlay panel.</p><p>The table editor shows:</p><ul><li><strong>Header cells</strong> — editable in the top row</li><li><strong>Data cells</strong> — editable in a grid layout</li><li><strong>Action chips</strong> — row and column controls</li><li><strong>Alignment controls</strong> — per-column alignment buttons in the header</li></ul><h2 id="edit-cells" tabindex="-1">Edit Cells <a class="header-anchor" href="#edit-cells" aria-label="Permalink to &quot;Edit Cells&quot;">​</a></h2><p>Click any cell in the grid to edit its content. Standard text editing applies — no Markdown needed inside cells.</p><div class="warning custom-block"><p class="custom-block-title">Pipe Characters in Cells</p><p>If you need a literal <code>|</code> character inside a cell, use the escaped form <code>\\|</code>. This is handled automatically by the table editor.</p></div><h2 id="add-and-remove-rows" tabindex="-1">Add and Remove Rows <a class="header-anchor" href="#add-and-remove-rows" aria-label="Permalink to &quot;Add and Remove Rows&quot;">​</a></h2><p>Use the <strong>action chips</strong> below the grid:</p><table tabindex="0"><thead><tr><th>Action</th><th>Result</th></tr></thead><tbody><tr><td><strong>+ Row</strong></td><td>Adds a new row at the bottom</td></tr><tr><td><strong>- Row</strong></td><td>Removes the last row</td></tr><tr><td><strong>+ Col</strong></td><td>Adds a column at the right</td></tr><tr><td><strong>- Col</strong></td><td>Removes the rightmost column</td></tr></tbody></table><p>After adding or removing rows/columns, the table editor stays active so you can continue editing.</p><h2 id="column-alignment" tabindex="-1">Column Alignment <a class="header-anchor" href="#column-alignment" aria-label="Permalink to &quot;Column Alignment&quot;">​</a></h2><p>Each header cell has an alignment control:</p><table tabindex="0"><thead><tr><th>Button</th><th>Alignment</th></tr></thead><tbody><tr><td><strong>L</strong> (left arrow)</td><td>Left-align the column (default)</td></tr><tr><td><strong>C</strong> (center)</td><td>Center-align the column</td></tr><tr><td><strong>R</strong> (right arrow)</td><td>Right-align the column</td></tr></tbody></table><p>Alignment is written as Markdown column separators:</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Left | Center | Right |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|:---|:---:|---:|</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="save-and-cancel" tabindex="-1">Save and Cancel <a class="header-anchor" href="#save-and-cancel" aria-label="Permalink to &quot;Save and Cancel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><strong>Save</strong></td><td>—</td><td>Writes the edited table back to Markdown source</td></tr><tr><td><strong>Cancel</strong></td><td><code>Esc</code></td><td>Discards changes and closes the editor</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Background Scroll Lock</p><p>While the table editor is open, background page scrolling is locked. The table content panel has its own scroll when the table is large. This prevents accidental position changes while editing.</p></div><h2 id="formatting-preservation" tabindex="-1">Formatting Preservation <a class="header-anchor" href="#formatting-preservation" aria-label="Permalink to &quot;Formatting Preservation&quot;">​</a></h2><p>When you edit a table that already exists in your note, Notely preserves the original Markdown formatting style (column spacing and delimiter style) where the table shape hasn&#39;t changed.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Large Tables</p><p>For very large tables, the inline editor panel scrolls independently. Use the header controls to keep the alignment buttons in view.</p></div><div class="tip custom-block"><p class="custom-block-title">Escaped Paths</p><p>Windows file paths (e.g. <code>C:\\Users\\name</code>) are handled safely — backslashes are preserved correctly in cell content.</p></div>`,31)])])}const g=t(l,[["render",i]]);export{b as __pageData,g as default};
